 1	import React, { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { isEmpty } from '@kubevirt-utils/utils/utils';
 6	import { Alert, AlertVariant, Stack, StackItem } from '@patternfly/react-core';
 7	
 8	type ErrorAlertProps = {
 9	  error: any | Error;
10	};
11	
12	const ErrorAlert: FC<ErrorAlertProps> = ({ error }) => {
13	  const { t } = useKubevirtTranslation();
14	  if (isEmpty(error)) return null;
15	
16	  return (
17	    <Alert isInline title={t('An error occurred')} variant={AlertVariant.danger}>
18	      <Stack hasGutter>
19	        <StackItem>{error.message}</StackItem>
20	        {error?.href && (
21	          <StackItem>
22	            <Link rel="noreferrer" target="_blank" to={error.href}>
23	              {error.href}
24	            </Link>
25	          </StackItem>
26	        )}
27	      </Stack>
28	    </Alert>
29	  );
30	};
31	
32	export default ErrorAlert;

